import heapq
from collections import defaultdict

class FrequentElementsStream:
    def __init__(self, k):
        self.k = k
        self.frequency = defaultdict(int)
        self.min_heap = []

    def add(self, num):
        # Update frequency of the current number
        self.frequency[num] += 1

        # Maintain a heap of size k
        if len(self.min_heap) < self.k:
            heapq.heappush(self.min_heap, (self.frequency[num], num))
        else:
            # Push new frequency into heap only if it's greater than the smallest
            if self.frequency[num] > self.min_heap[0][0]:
                heapq.heappop(self.min_heap)
                heapq.heappush(self.min_heap, (self.frequency[num], num))

    def get_k_most_frequent(self):
        # Extract elements from the heap and sort them by frequency
        return sorted(self.min_heap, key=lambda x: (-x[0], x[1]))

# Example usage:
stream = FrequentElementsStream(3)
numbers = [1, 1, 1, 2, 2, 3]

for num in numbers:
    stream.add(num)

most_frequent = stream.get_k_most_frequent()
print([num for _, num in most_frequent])  # Output the k most frequent elements
